import type { _OverlayTooltipGeometryTypes as GeometryTypes } from '@dynatrace/strato-components/charts';

import {
  useGeoOverlayTooltipState,
  useGeoTooltipSync,
  useOverlayTooltipSelector,
} from './use-geo-tooltip-sync.js';
import { useGetPosition } from './use-get-position.js';
import { useSelector } from '../store/selectors.js';

export const useGeoLayerTooltip = <T>(geometryType: GeometryTypes) => {
  const enabled = useSelector(({ tooltip }) => tooltip.enabled);

  const { data, pinned, inBounds } = useGeoOverlayTooltipState<T>();

  const forceHideTooltip = !pinned && (!inBounds || !enabled);
  const markerPosition = useGetPosition(pinned, !forceHideTooltip);

  const storePosition = useOverlayTooltipSelector((state) =>
    state.inBounds &&
    typeof state.absoluteX === 'number' &&
    typeof state.absoluteY === 'number'
      ? { x: state.absoluteX, y: state.absoluteY }
      : null,
  );

  const position = pinned ? markerPosition : storePosition;

  useGeoTooltipSync(position, pinned, geometryType, data ?? undefined);

  return { data, pinned, inBounds, position };
};
